class Solution(object):
    def minCost(self, nums):
        n = len(nums)
        # After each pair removal from first 3, one element 'carries over'.
        # dp[i][j] = min cost to remove nums[i..n-1] where j is the carry-over element
        # (j=0 means no carry-over)
        # State: (start_index, carry_over_value)
        from functools import lru_cache
        @lru_cache(maxsize=None)
        def dp(i, carry):
            # Remove elements starting at index i with carry-over 'carry' (0 = none)
            remaining = n - i
            if carry != 0:
                remaining += 1
            if remaining == 0:
                return 0
            if remaining == 1:
                v = nums[i] if carry == 0 else (carry if i >= n else max(carry, nums[i]))
                # Just one element left (either carry or first)
                if carry != 0 and i < n:
                    return max(carry, nums[i])
                elif carry != 0:
                    return carry
                else:
                    return nums[i]
            if remaining == 2:
                if carry != 0 and i < n:
                    return max(carry, nums[i])
                elif i + 1 < n:
                    return max(nums[i], nums[i+1])
                return carry
            # At least 3 elements. Front 3 are: carry (if any) + nums[i], nums[i+1], ...
            if carry != 0:
                front = [carry, nums[i], nums[i+1]]
                # Choose 2 of 3 to remove; keep 1 as new carry
                best = float('inf')
                for skip in range(3):
                    removed = [front[k] for k in range(3) if k != skip]
                    cost = max(removed)
                    best = min(best, cost + dp(i+2, front[skip]))
                return best
            else:
                front = [nums[i], nums[i+1], nums[i+2]]
                best = float('inf')
                for skip in range(3):
                    removed = [front[k] for k in range(3) if k != skip]
                    cost = max(removed)
                    best = min(best, cost + dp(i+3, front[skip]))
                return best
        return dp(0, 0)
